// ============================================================
// 節點：指令解析（規則式，不依賴 AI）
// ============================================================

const CONFIG = {
  warehouses: ['TAO1', 'TAO3', 'TAO4', 'TAO5', 'TAO6', 'TAO7', 'TAO10'],
  intentKeywords: [
    { keywords: ['病假統計'], intent: 'sick_leave_stats' },
    { keywords: ['請假統計'], intent: 'leave_stats' },
    { keywords: ['請假狀況', '請假'], intent: 'leave_status' },
    { keywords: ['出勤人員', '出勤明細', '出勤報表'], intent: 'attendance_detail' },
    { keywords: ['出勤統計'], intent: 'attendance_stats' },
  ],
  leaveTypeKeywords: [
    { keywords: ['病假', '病'], leaveType: '病假' },
    { keywords: ['事假', '事'], leaveType: '事假' },
    { keywords: ['特休', '特'], leaveType: '特休' },
    { keywords: ['曠職', '曠'], leaveType: '曠職' },
  ],
};

const query = ($input.first().json.body?.query || '').trim();
if (!query) {
  return [{ json: { success: false, error: '請提供查詢指令（query 欄位為空）', hint: '範例：4/2請假狀況、查詢TAO1 4/2病假' } }];
}

function parseDate(q) {
  const now = new Date();
  const currentYear = now.getFullYear();
  let m = q.match(/(\d{4})[\/-](\d{1,2})[\/-](\d{1,2})/);
  if (m) return `${m[1]}-${String(m[2]).padStart(2, '0')}-${String(m[3]).padStart(2, '0')}`;
  m = q.match(/(\d{1,2})[\/-](\d{1,2})/);
  if (m) return `${currentYear}-${String(m[1]).padStart(2, '0')}-${String(m[2]).padStart(2, '0')}`;
  return null;
}
function parseIntent(q) {
  for (const rule of CONFIG.intentKeywords) { for (const kw of rule.keywords) { if (q.includes(kw)) return rule.intent; } }
  return 'attendance_detail';
}
function parseWarehouses(q) {
  if (/全部倉|所有倉|全倉/.test(q)) return CONFIG.warehouses.slice();
  const found = [];
  for (const wh of CONFIG.warehouses) { if (q.toUpperCase().includes(wh)) found.push(wh); }
  return found.length > 0 ? found : CONFIG.warehouses.slice();
}
function parseLeaveType(q) {
  for (const rule of CONFIG.leaveTypeKeywords) { for (const kw of rule.keywords) { if (q.includes(kw)) return rule.leaveType; } }
  return '';
}

const date = parseDate(query);
if (!date) {
  return [{ json: { success: false, error: '無法解析日期', hint: '支援格式：4/2、04/02、2026/4/2、2026-04-02', originalQuery: query } }];
}
const intent = parseIntent(query);
return [{ json: { success: true, parsed: { intent, date, warehouse: parseWarehouses(query), leaveType: parseLeaveType(query), needReport: ['sick_leave_stats','leave_stats','attendance_stats'].includes(intent) }, originalQuery: query } }];

// ============================================================
// 節點：組裝讀取參數（含 token）
// ============================================================
const CONFIG = {
  spreadsheetMap: {
    'TAO1':  '1_bhGQdx0YH7lsqPFEq5___6_Nwq_gbelJmIHv0bmaIE',
    'TAO3':  '1cffI2jIVZA1uSiAyaLLXXgPzDByhy87xznaN85O7wEE',
    'TAO4':  '1tVxQbV0298fn2OXWAF0UqZa7FLbypsatciatxs4YVTU',
    'TAO5':  '1jzVXC6gt36hJtlUHoxtTzZLMNj4EtTsd4k8eNB1bdiA',
    'TAO6':  '1wwPLSLjl2abfM_OMdTNI9PoiPKo3waCV_y0wmx2DxAE',
    'TAO7':  '16nGCqRO8DYDm0PbXFbdt-fiEFZCXxXjlOWjKU67p4LY',
    'TAO10': '1y0w49xdFlHvcVtgtG8fq6zdrF26y8j7HMFh5ujzUyR4',
  },
  intentSheetType: {
    'leave_status': 'leave', 'sick_leave_stats': 'leave', 'leave_stats': 'leave',
    'attendance_detail': 'work', 'attendance_stats': 'work',
  },
  sheetKeywords: {
    leave: ['班表', '出勤記錄', '假況'],
    work:  ['出勤時數', '出勤時間', '工時'],
  },
};

const prevNode = $('指令解析').first().json;
const parsed = prevNode.parsed;
const sheetType = CONFIG.intentSheetType[parsed.intent] || 'leave';
const results = [];
for (const wh of parsed.warehouse) {
  const sid = CONFIG.spreadsheetMap[wh];
  if (!sid) continue;
  results.push({ json: {
    warehouse: wh, spreadsheetId: sid, sheetType,
    sheetKeywords: CONFIG.sheetKeywords[sheetType],
    intent: parsed.intent, date: parsed.date,
    leaveType: parsed.leaveType, needReport: parsed.needReport,
    originalQuery: prevNode.originalQuery,
    metaUrl: `https://sheets.googleapis.com/v4/spreadsheets/${sid}?fields=sheets.properties.title`,
  }});
}
return results;

// ============================================================
// 節點：解析分頁名稱，組裝資料讀取 URL
// ============================================================
const CONFIG = {
  sheetKeywords: {
    leave: ['班表', '出勤記錄', '假況'],
    work:  ['出勤時數', '出勤時間', '工時'],
  },
};

let prevData;
try { prevData = $('組裝讀取參數').first().json; } catch(e) { prevData = $input.first().json; }
const metaResponse = $input.first().json;
const warehouse = prevData.warehouse;
const spreadsheetId = prevData.spreadsheetId;
const sheetType = prevData.sheetType;
const keywords = CONFIG.sheetKeywords[sheetType] || CONFIG.sheetKeywords.leave;

if (metaResponse.error || !metaResponse.sheets) {
  return [{ json: { ...prevData, allSheetNames: [], warning: `${warehouse} 無法取得分頁列表：${metaResponse.error?.message || JSON.stringify(metaResponse).substring(0,200)}`, dataUrl: '', success: false } }];
}
const allSheetNames = metaResponse.sheets.map(s => s.properties.title);
let targetSheet = null;
let warning = null;
for (const kw of keywords) {
  const found = allSheetNames.find(name => name.includes(kw));
  if (found) { targetSheet = found; break; }
}
if (!targetSheet) {
  targetSheet = allSheetNames[0] || 'Sheet1';
  warning = `${warehouse} 找不到含 [${keywords.join(', ')}] 的分頁，已使用「${targetSheet}」。所有分頁：${allSheetNames.join(', ')}`;
}
const dataUrl = `https://sheets.googleapis.com/v4/spreadsheets/${spreadsheetId}/values/${encodeURIComponent(targetSheet)}?majorDimension=ROWS`;
return [{ json: { ...prevData, sheetName: targetSheet, allSheetNames, warning, dataUrl, success: true } }];

// ============================================================
// 節點：資料標準化
// ============================================================
const CONFIG = {
  workFieldMapping: {
    date: ['日期','Date','date'], department: ['組別','部門','Department','department','組','Group'],
    shift: ['班別','Shift','shift','班次'], name: ['姓名','Name','name','員工姓名'],
    workHours: ['工作總時數','工時','Hours','workHours','Work Hours','總工時'],
    overtimeHours: ['加班總時數','OvertimeHours','Overtime Hours','overtimeHours','加班時數','加班'],
    note: ['備註','Note','note','Remark','說明'],
    attendanceStatus: ['出勤狀態','Status','status','attendanceStatus'],
    leaveType: ['假況','請假','LeaveType','leaveType','Leave Type','假別'],
  },
  leaveStatusMapping: {
    '病假':'病假','病':'病假','sick':'病假','sick leave':'病假',
    '事假':'事假','事':'事假','personal leave':'事假',
    '特休':'特休','特':'特休','annual leave':'特休',
    '曠職':'曠職','曠':'曠職','absent':'曠職',
    '出勤':'出勤','正常':'出勤','attendance':'出勤','present':'出勤',
    '休假':'休假','休':'休假','公假':'公假','公':'公假',
    '產假':'產假','喪假':'喪假','婚假':'婚假',
  },
  leaveDateStartCol: 7,
};

let prevData;
try { prevData = $('解析分頁並組裝URL').first().json; } catch(e) { prevData = {}; }
const apiResponse = $input.first().json;
const warehouse = prevData.warehouse || '';
const sheetType = prevData.sheetType || 'work';
const sheetName = prevData.sheetName || '';
const allSheetNames = prevData.allSheetNames || [];
const date = prevData.date || '';
const intent = prevData.intent || '';
const leaveType = prevData.leaveType || '';
const needReport = prevData.needReport || false;
const originalQuery = prevData.originalQuery || '';
const prevWarning = prevData.warning || null;

if (apiResponse.error || !apiResponse.values) {
  return [{ json: { warehouse, sheetType, sheetName, allSheetNames, date, intent, leaveType, needReport, originalQuery, warning: prevWarning, rows: [], totalRows: 0, success: false, error: `${warehouse}「${sheetName}」無資料` } }];
}
const allRows = apiResponse.values || [];
const headers = allRows[0] || [];
const rawRows = allRows.slice(1);

function findCol(hdrs, aliases) { for (const a of aliases) { const i = hdrs.findIndex(h => h && h.trim() === a); if (i !== -1) return i; } return -1; }
function normStatus(val) {
  if (!val || val.trim() === '') return { status: '', resolved: true };
  const v = val.trim().toLowerCase();
  for (const [k, m] of Object.entries(CONFIG.leaveStatusMapping)) { if (v === k.toLowerCase()) return { status: m, resolved: true }; }
  return { status: val.trim(), resolved: false, unresolvedStatus: true };
}

let rows = [];
if (sheetType === 'work') {
  const colMap = {};
  for (const [f, aliases] of Object.entries(CONFIG.workFieldMapping)) colMap[f] = findCol(headers, aliases);
  for (const row of rawRows) {
    const g = (f) => { const i = colMap[f]; return i >= 0 && row[i] !== undefined ? String(row[i]).trim() : ''; };
    const si = normStatus(g('attendanceStatus') || g('leaveType'));
    rows.push({ date: g('date'), department: g('department'), shift: g('shift'), name: g('name'), workHours: g('workHours'), overtimeHours: g('overtimeHours'), attendanceStatus: si.status, leaveType: si.status, note: g('note'), warehouse, ...(si.unresolvedStatus ? { unresolvedStatus: true } : {}) });
  }
} else {
  const dsc = CONFIG.leaveDateStartCol;
  const ni = findCol(headers, ['姓名','Name','name','員工姓名']);
  const di = findCol(headers, ['組別','部門','Department','department','組','Group']);
  const si = findCol(headers, ['班別','Shift','shift','班次']);
  const dateHeaders = headers.slice(dsc);
  for (const row of rawRows) {
    const pn = ni >= 0 ? String(row[ni] || '').trim() : '';
    const dp = di >= 0 ? String(row[di] || '').trim() : '';
    const sh = si >= 0 ? String(row[si] || '').trim() : '';
    if (!pn) continue;
    for (let i = 0; i < dateHeaders.length; i++) {
      const cv = row[dsc + i];
      if (cv === undefined || cv === null || String(cv).trim() === '') continue;
      const st = normStatus(String(cv));
      rows.push({ date: dateHeaders[i] ? String(dateHeaders[i]).trim() : '', department: dp, shift: sh, name: pn, workHours: '', overtimeHours: '', attendanceStatus: st.status, leaveType: st.status, note: '', warehouse, ...(st.unresolvedStatus ? { unresolvedStatus: true } : {}) });
    }
  }
}
return [{ json: { warehouse, sheetType, sheetName, allSheetNames, date, intent, leaveType, needReport, originalQuery, warning: prevWarning, rows, totalRows: rows.length, success: true } }];

// ============================================================
// 節點：合併所有倉別資料
// ============================================================
const allItems = $input.all();
const mergedRows = [], warnings = [], errors = [];
let date='', intent='', leaveType='', needReport=false, originalQuery='';
const warehouseList = [];
for (const item of allItems) {
  const d = item.json;
  if (!date) date = d.date; if (!intent) intent = d.intent;
  if (!leaveType) leaveType = d.leaveType; if (!needReport) needReport = d.needReport;
  if (!originalQuery) originalQuery = d.originalQuery;
  warehouseList.push(d.warehouse);
  if (d.warning) warnings.push(d.warning);
  if (!d.success) { errors.push(d.error || `${d.warehouse} 讀取失敗`); continue; }
  if (d.rows && d.rows.length > 0) mergedRows.push(...d.rows);
}
return [{ json: { date, intent, leaveType, needReport, originalQuery, warehouses: warehouseList, rows: mergedRows, totalRows: mergedRows.length, warnings: warnings.length > 0 ? warnings : undefined, errors: errors.length > 0 ? errors : undefined, success: errors.length === 0 } }];

// ============================================================
// 節點：查詢與統計
// ============================================================
const CONFIG = { attendanceValues: ['出勤', '正常', ''] };
const data = $input.first().json;
const { date, intent, leaveType, needReport, originalQuery, rows, warehouses, warnings, errors } = data;

function matchDate(rd, td) {
  if (!rd || !td) return false;
  rd = String(rd).trim(); td = String(td).trim();
  if (rd === td) return true;
  const p = td.split('-'); if (p.length !== 3) return false;
  const [tY,tM,tD] = p.map(Number);
  let m = rd.match(/^(\d{1,2})[\/-](\d{1,2})$/); if (m) return +m[1]===tM && +m[2]===tD;
  m = rd.match(/^(\d{4})[\/-](\d{1,2})[\/-](\d{1,2})$/); if (m) return +m[1]===tY && +m[2]===tM && +m[3]===tD;
  return false;
}
const df = rows.filter(r => matchDate(r.date, date));
let result = {};
switch (intent) {
  case 'leave_status': {
    const lr = df.filter(r => { const s=r.attendanceStatus||r.leaveType||''; return s && !CONFIG.attendanceValues.includes(s); });
    const fr = leaveType ? lr.filter(r => (r.leaveType||r.attendanceStatus)===leaveType) : lr;
    result = { success:true, query:originalQuery, intent, date, summaryText:`${date} 請假狀況：共 ${fr.length} 人請假`+(leaveType?`（${leaveType}）`:'')+`，倉別：${warehouses.join(', ')}`, totals:{totalLeave:fr.length, byWarehouse:{}, byLeaveType:{}}, rows:fr };
    for (const r of fr) { result.totals.byWarehouse[r.warehouse]=(result.totals.byWarehouse[r.warehouse]||0)+1; const lt=r.leaveType||r.attendanceStatus||'未分類'; result.totals.byLeaveType[lt]=(result.totals.byLeaveType[lt]||0)+1; }
    break;
  }
  case 'sick_leave_stats': {
    const sr = df.filter(r => (r.leaveType||r.attendanceStatus||'').trim()==='病假');
    result = { success:true, query:originalQuery, intent, date, summaryText:`${date} 病假統計：共 ${sr.length} 人，倉別：${warehouses.join(', ')}`, totals:{totalSickLeave:sr.length, byWarehouse:{}}, rows:sr };
    for (const r of sr) result.totals.byWarehouse[r.warehouse]=(result.totals.byWarehouse[r.warehouse]||0)+1;
    break;
  }
  case 'leave_stats': {
    const lr = df.filter(r => { const s=r.attendanceStatus||r.leaveType||''; return s && !CONFIG.attendanceValues.includes(s); });
    result = { success:true, query:originalQuery, intent, date, summaryText:`${date} 請假統計：共 ${lr.length} 人，倉別：${warehouses.join(', ')}`, totals:{totalLeave:lr.length, byWarehouse:{}, byLeaveType:{}}, rows:lr };
    for (const r of lr) { result.totals.byWarehouse[r.warehouse]=(result.totals.byWarehouse[r.warehouse]||0)+1; const lt=r.leaveType||r.attendanceStatus||'未分類'; result.totals.byLeaveType[lt]=(result.totals.byLeaveType[lt]||0)+1; }
    break;
  }
  case 'attendance_detail': {
    result = { success:true, query:originalQuery, intent, date, summaryText:`${date} 出勤明細：共 ${df.length} 筆，倉別：${warehouses.join(', ')}`, totals:{totalRecords:df.length, byWarehouse:{}, byDepartment:{}, byShift:{}}, rows:df };
    for (const r of df) { result.totals.byWarehouse[r.warehouse]=(result.totals.byWarehouse[r.warehouse]||0)+1; if(r.department) result.totals.byDepartment[r.department]=(result.totals.byDepartment[r.department]||0)+1; if(r.shift) result.totals.byShift[r.shift]=(result.totals.byShift[r.shift]||0)+1; }
    break;
  }
  case 'attendance_stats': {
    const tw=df.reduce((s,r)=>s+(parseFloat(r.workHours)||0),0), to=df.reduce((s,r)=>s+(parseFloat(r.overtimeHours)||0),0);
    result = { success:true, query:originalQuery, intent, date, summaryText:`${date} 出勤統計：${df.length} 人，工時 ${tw.toFixed(1)}h，加班 ${to.toFixed(1)}h，倉別：${warehouses.join(', ')}`, totals:{totalRecords:df.length, totalWorkHours:tw.toFixed(1), totalOvertimeHours:to.toFixed(1), byWarehouse:{}}, rows:df };
    for (const r of df) { if(!result.totals.byWarehouse[r.warehouse]) result.totals.byWarehouse[r.warehouse]={count:0,workHours:0,overtimeHours:0}; result.totals.byWarehouse[r.warehouse].count++; result.totals.byWarehouse[r.warehouse].workHours+=parseFloat(r.workHours)||0; result.totals.byWarehouse[r.warehouse].overtimeHours+=parseFloat(r.overtimeHours)||0; }
    for (const w of Object.keys(result.totals.byWarehouse)) { result.totals.byWarehouse[w].workHours=result.totals.byWarehouse[w].workHours.toFixed(1); result.totals.byWarehouse[w].overtimeHours=result.totals.byWarehouse[w].overtimeHours.toFixed(1); }
    break;
  }
  default: result = { success:false, query:originalQuery, error:`無法識別意圖：${intent}` };
}
if (warnings?.length) result.warnings = warnings;
if (errors?.length) { result.errors = errors; if (result.rows?.length===0) { result.success=false; result.summaryText='部分倉別讀取失敗'; } }
if (result.rows?.length===0 && result.success) { result.success=false; result.summaryText=`${date} 查無符合條件的資料（${warehouses.join(', ')}）`; }
result.emailReady=true; result.emailSubject=`[出勤報表] ${date} ${intent} - ${warehouses.join(', ')}`; result.emailBody=result.summaryText||'';
return [{ json: result }];
